var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마침 한 권을 다 읽은 참이었습니다. 늦으셨군요.","JPN":"ちょうど一冊読み終えたところです。遅かったのですね。","ENG":"I have just finished reading an entire book. You are late.","TWN":"遲到囉，我都讀完一本書了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야, 꼰대. 네가 왜 여기 있어?","JPN":"なんだよ、ばばあ。なんであんたがここにいるわけ？","ENG":"Huh? Snob? What are you doing here?","TWN":"搞什麼，四眼姊姊，你怎麼會在這裡？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님. 루체 자매님께 말버릇이 그게 뭐예요?","JPN":"シスター・ルーパー。シスター・ルーチェになんて口の利き方ですか。","ENG":"Sister Looper, you shouldn't talk to Sister Luce like that.","TWN":"洛珀姊妹，怎麼可以這樣對露契姊妹說話呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"여전히 무례하군요. 시스터 루퍼.","JPN":"相変わらず無礼ですね。シスタールーパー。","ENG":"Still rude as ever I see, Sister Looper.","TWN":"你還是一樣沒大沒小的呢，洛珀姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 저는 시스터 넬슨처럼 무른 성격이 아닙니다.","JPN":"ですが、私はシスターネルソンのように甘い性格ではありません。","ENG":"However, I will am not as gentle as Sister Nelson.","TWN":"不過我可不像尼爾森姊妹那麼溫柔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 밑에서 일하시는 동안, 기꺼이 조신한 시스터로 만들어드리죠.","JPN":"私の下で働く間、慎み深いシスターになるよう、喜んで再教育いたしましょう。","ENG":"While you are working for me, I will gladly train you to become a well-behaved Sister.","TWN":"你在我底下做事的這段時間，我很樂意把你打造成一個端莊的姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"미사 때 포도주 대신 보드카라도 마셨나? 누가 누구 밑에서 일해?","JPN":"ミサでブドウ酒の代わりにウォッカでも飲んだ？　誰が誰の下で働くって？","ENG":"Who switched out your wine for vodka during Mass? Who's working under who now?","TWN":"彌撒的時候你喝的不是葡萄酒，而是伏特加是不是？誰要在你底下做事？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님, 그 말씀은?","JPN":"シスター・ルーチェ、それはつまり？","ENG":"Sister Luce, what you mean is...?","TWN":"露契姊妹，那是什麼意思呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 서거하시고 행정처리는 아직입니다만.","JPN":"猊下が逝去なさって、行政的な処理はまだ行われておりませんが。","ENG":"His Eminence has passed away, but the administrative process is still pending.","TWN":"主教安息後，雖然還有些行政流程要走，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"금일부로 제 9호 기적심의회의 집행 사제로 배속되었습니다.","JPN":"今日をもって第9号奇跡審議会の執行司祭として配属されました。","ENG":"Effective immediately, I have been assigned as the Inquisitorial Priest of Miracle Investigation Council 9.","TWN":"但從今天起，我將接任第9奇蹟議會執行祭司一職。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"피차 익숙한 얼굴들이니 인사치레는 생략하죠.","JPN":"お互い知った顔ぶれですから、挨拶は省きましょう。","ENG":"I shall skip the introductions as we are already acquainted.","TWN":"既然大家都已經見過面，自我介紹的部分就先省略吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리 대신 꼰대 안경이라고? 환장하겠네.","JPN":"のっぽの代わりに眼鏡ばばあ？　あり得ない。","ENG":"Sheesh...! First Long Legs, and now it's Specky Snob?","TWN":"四眼姊姊要取代高個子？合理嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"집행 사제라고 하시면 설마…….","JPN":"執行司祭とおっしゃいますと、まさか……","ENG":"If you're the Inquisitorial Priest, then...","TWN":"你說執行祭司……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 지시입니다.","JPN":"聖皇庁の指示です。","ENG":"It is an order from the Holy Curia.","TWN":"是聖皇廳下的令。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"현 시간부로, 우리 제 9호 기적심의회는 요한 추기경을 살해한 베네딕트 콘스탄틴을 추격하게 되었습니다.","JPN":"現時点をもって、第9号奇跡審議会はヨハン枢機卿を殺したベネディクト・コンスタンティンを追撃することになりました。","ENG":"As of this time, Miracle Investigation Council 9 will begin its investigation into Cardinal Johan's murderer, Benedict Constantine.","TWN":"即刻起，我們第9奇蹟議會將捉拿殺害約翰樞機主教的犯人，本尼迪克特·康斯坦丁。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"변절자의 목적을 읽어내는 것과 그 죗값을 치르게 하는 것. 그것이 우리의 목표죠.","JPN":"宗旨替えの目的を読むこととその罪を償わせること。それが私たちの目標です。","ENG":"Read the traitor's objectives and make him pay for his sins. That will be our goal.","TWN":"我們的目標是，讀出叛徒的目的，以及讓他付出應有的代價。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……아니요. 루체 자매님.","JPN":"……いいえ。シスター・ルーチェ。","ENG":"No, Sister Luce.","TWN":"……不，露契姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저희는 아직 루체 자매님의 이야기를 듣지 못했어요.","JPN":"私たちはまだあなたのお話を聞いておりませんわ。","ENG":"We still haven't heard your side of the story.","TWN":"我們都還沒聽過你的說法。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님이 성무를 은폐하려 했다는 것도, 이단과 내통했다는 것도.","JPN":"神父様が聖務を隠ぺいしようとしたということも、異端と内通したということも。","ENG":"Of how Father tried to cover up the sacred mission, of how he conspired with a heretic...","TWN":"不管是神父想要掩蓋聖務，或是與異端私通，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그리고 예하를 살해하고 도주했다는 것도…….","JPN":"そして猊下を殺して逃走したということも……","ENG":"And how he murdered his Eminence and fled...","TWN":"還是殺害主教，這些事……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저희가 알던 신부님의 모습과는 전혀 다른 걸요.","JPN":"私たちの知る神父様のお姿とはまったく違うのですから。","ENG":"Those are all completely different from the Father we know.","TWN":"都不像是我們認識的神父會做的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그건 절 의심하는 겁니까, 시스터 넬슨?","JPN":"私を疑っているということですか？　シスターネルソン。","ENG":"Are you doubting me, Sister Nelson?","TWN":"你是在懷疑嗎，尼爾森姊妹？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 아뇨! 이건 그런 게 아니라…….","JPN":"い、いいえ！　そういうことではなくて……","ENG":"N-not at all! It's just that...","TWN":"不…不是的，我不是那個意思……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"후후, 좋은 자세로군요.","JPN":"ふふ、いい姿勢ですね。","ENG":"Ha ha, I like how you think.","TWN":"呵呵，態度很不錯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이제야 조금 심의회 멤버다워졌습니다.","JPN":"これで少しは審議会のメンバーらしくなりました。","ENG":"Now you seem more like a member of the Investigation Council.","TWN":"這才稍微像是議會的成員。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"Pardon?","TWN":"……什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"뭐 좋습니다. 가끔은 읽히는 쪽이 되는 것도 그리 나쁘지 않겠죠.","JPN":"まあ、いいでしょう。たまには読まれる方になるのも悪くありません。","ENG":"No matter. It is not so bad being read from time to time.","TWN":"沒事，偶爾成為被讀的一方也沒什麼不好的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"열람시켜드리겠습니다. 그날 있었던 일을……","JPN":"閲覧させてさしあげましょう。あの日の出来事を……","ENG":"I shall let you browse what happened that day...","TWN":"那就請你們閱讀一下囉，那天是這樣的……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"00:18 AM. 성황청 \\n<color=#ffd34c>기적심의회 제 2본부</color>","JPN":"00:18 AM。聖皇庁\\n<color=#ffd34c>奇跡審議会第2本部</color>","ENG":"00:18. Holy Curia \\n<color=#ffd34c>Miracle Investigation Council's 2nd HQ</color>","TWN":"00:18 AM. 聖皇廳 \\n<color=#ffd34c>奇蹟議會第2總部</color>"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회 본부에서 총성이라고?","JPN":"審議会本部から銃声が？","ENG":"A gun shot at the Investigation Council's HQ?","TWN":"議會總部傳來槍聲？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다른 집행 사제들은 대체 뭘 하고 있길래?","JPN":"他の執行司祭は一体何をしてるの？","ENG":"What were the other Inquisitorial Priests doing?","TWN":"其他執行祭司到底在做什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"수, 수녀님……! 여긴 위험합니다!!","JPN":"し、シスター……！　ここは危険です！！","ENG":"S-sister...! It's too dangerous here!!","TWN":"修…修女……！這裡很危險！！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"심문을 받던 집행 사제가 갑자기 돌변해서……!","JPN":"審問を受けていた執行司祭が急変して……！","ENG":"The Inquisitorial Priest who was being questioned suddenly changed and─!","TWN":"執行祭司原本在接受訊問，結果突然情勢一變……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으, 으윽!!","JPN":"う、ううっ！！","ENG":"E-errgh!!","TWN":"呃呃！！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……베네딕트 콘스탄틴.","JPN":"……ベネディクト・コンスタンティン。","ENG":"Benedict Constantine...","TWN":"……本尼迪克特·康斯坦丁。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"운이 나쁘군.","JPN":"ついてないな。","ENG":"How unlucky.","TWN":"真不走運。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이런 곳에서, 이런 식으로…… 옛 동료와 조우할 줄이야.","JPN":"このようなところで、このような形で……昔の仲間と遭遇するとは。","ENG":"To run into an old colleague like this... here of all places.","TWN":"沒想到會在這種地方，以這種方式……遇見老同事。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"거기서 비켜라, 비블리데. 지금은 널 상대해 주고 있을 시간이 없다.","JPN":"そこをどけ、ビブリデ。今君の相手をしている暇はない。","ENG":"Get out of my way, Biblide. I have no time for you.","TWN":"布莉黛，好狗不擋路，我現在沒時間陪你玩。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……언젠가 이런 날이 올 거라고 생각은 했는데.","JPN":"……いつかこんな日が来るとは思っていましたけど。","ENG":"I had a feeling this day would come.","TWN":"……我早就知道會有這麼一天，"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그런데 그 날이 하필, 예하께서 당신을 심문하는 오늘이 될 줄은 몰랐군요.","JPN":"その日がよりによって猊下があなたを審問する日になるとは。","ENG":"But I did not expect it would be today, the day if your interrogation with his Eminence.","TWN":"只是沒想到偏偏是主教審問你的這一天。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 피칠갑을 한 꼴을 보니, 결과가 그리 만족스럽지 않았나 보죠?","JPN":"その血まみれの姿を見ると、結果は満足の行くものではなかったようですね。","ENG":"Blood stains everywhere... I presume you were not happy about the results?","TWN":"看你沾滿鮮血的樣子，看來是對結果不甚滿意是吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"알고 있습니까?","JPN":"知っていますか？","ENG":"Did you know?","TWN":"你知道嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서는 그런 당신조차 걱정하며 내게 조사를 부탁하셨어요.","JPN":"猊下はそんなあなたでさえ心配して、私に調査を依頼なさったことを。","ENG":"His Eminence was worried about you, and asked me to investigate.","TWN":"主教還很擔心你，甚至還拜託我進行調查。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 죗값을 덜어주려고…….","JPN":"あなたの罪を減らすために……","ENG":"He wanted me to lighten your guilt...","TWN":"希望能減輕你的刑責……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그런 예하께…… 당신은 무슨 짓을 저지른 겁니까?","JPN":"そんな猊下に……あなたはいったい何をしたのですか？","ENG":"And yet... This is how you repay him?","TWN":"而你竟然對主教……你到底在做什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"*Sigh...*","TWN":"……哀。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그 자는 내 이야기를 이해하지 못하고 나를 죽이려 했다.","JPN":"あの者は私の話を理解できず、殺そうとした。","ENG":"That man attempted to kill me without even trying to understand me.","TWN":"他根本不理解我的想法，還想殺我。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"죽지 않기 위해 죽였다. 그뿐이다.","JPN":"生きるために殺した。それだけだ。","ENG":"All I did was kill him before he could kill me. That is all.","TWN":"我不殺他，死的就會是我，我只是在自保。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이해하지 못했다고?","JPN":"理解できなかった？","ENG":"Not understand you?","TWN":"他不理解你？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"겨우 그런 이유로 가족 같은 분을……!","JPN":"たかがそんな理由で家族のような方を……！","ENG":"He was like family, and you murdered him because...!","TWN":"就因為這個原因，把如同家人般的……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"가족? 무슨 소리지?","JPN":"家族？　どういうことだ。","ENG":"Family? Do you hear yourself?","TWN":"家人？你在胡說什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"같은 자에게 거둬져, 같은 것을 배웠다고 모두 가족이 되는 것은 아닐 텐데.","JPN":"同じ者に引き取られ、同じことを学んだとしてもみんな家族になるわけではないはずだ。","ENG":"Being raised, fed, and brought up by the same person does not make us \\"family\\".","TWN":"就算被同一個人收養，讀一樣的書，也不代表我們就是一家人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"지금 이 순간에도 조금씩 세상은 멸망을 향해 다가가고 있다.","JPN":"今この瞬間にも世界は少しずつ滅亡に近づいている。","ENG":"The end of the world is slowly approaching even as we speak.","TWN":"即使是現在，世界也朝著滅亡更近一步。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마음만 먹으면 이 세계를 박살내어 버릴 존재들이 심연 속에서 때를 기다리고 있지.","JPN":"その気になれば、この世界を壊せる存在が深淵の中で時を待っているのだ。","ENG":"In the depths of the abyss, there are unimaginable beings that could destroy this world on a whim.","TWN":"只要下定決心，就可以將世界毀滅掉的存在，正在深淵裡伺機而動。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런데 우리의 신은 무엇을 하고 있지?","JPN":"それなのに私たちの神は何をしている？","ENG":"But what is \\"our\\" God doing?","TWN":"但我們的神有什麼作為呢？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……그리고 신의 대리인을 자청하며 거들먹거리던 우리 사제들은?","JPN":"……そして神の代理人を自称しながら偉ぶっていた私たち司祭は？","ENG":"And what about our arrogant priests who call themselves the messengers of God?","TWN":"……還有那些以神的代言人自居，而得意洋洋的祭司們呢？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"닥치세요! 변절자!!","JPN":"黙りなさい！　変節者！！","ENG":"Shut up! Betrayer!!","TWN":"你閉嘴！叛徒！！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그딴 소리를 지껄이는 걸 보니 예하께서 왜 당신을 심판하려 했는지 안 봐도 알 것 같군요!","JPN":"そんなことを言っているのを見ると、猊下がどうしてあなたを審判しようとしたのかわかるような気がします！","ENG":"I can see why his Eminence sentenced you to death after hearing you speak!","TWN":"光是聽你說這些，就可以知道主教為何要審判你！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"허나, 그 이상의 신성 모독은 용납하지 않겠습니다!","JPN":"ですが、それ以上の神聖冒涜は許しません！","ENG":"Nevertheless, I will not tolerate further blasphemy!","TWN":"但是，我不准你再繼續褻瀆我們的神！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아무래도 곱게 길을 비켜줄 것 같지는 않군.","JPN":"どうやら素直に道を開けてくれそうにないな。","ENG":"I see you are not going to back down easily.","TWN":"看來你是不會乖乖讓開的。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만 나는 그 날 깨달았다. 구원은 인간 스스로가 쟁취해야 한다는 것을.","JPN":"私はあの日気づいてしまったんだ。救いは人間自らが勝ち取るべきものであると。","ENG":"There is a truth that I have come to realize. That salvation must be obtained by my man himself.","TWN":"這是我在那一天體認到的，原來救贖是要靠人類自己去爭取的。"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"정말로 스스로가 옳다고 믿는다면…… 이 자리에서 나를 심판해 봐라, 비블리데.","JPN":"本当に自身が正しいと信じているなら……この場で私を審判してみろ、ビブリデ。","ENG":"If you truly believe you are right... then bring judgment down upon me right now, Biblide.","TWN":"若你真的認為你是對的……就在這裡當場審判我吧，布莉黛！"},"stage":{"bg":"HALL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};